import app from 'flarum/forum/app';
import Modal from 'flarum/common/components/Modal';
import AuditBrowser from '../../common/components/AuditBrowser';
export default class UserAuditModal extends Modal {
  className() {
    return 'AuditModal UserAuditModal';
  }
  title() {
    return app.translator.trans('flarum-audit.forum.modal.user-title');
  }
  content() {
    return m(AuditBrowser, {
      baseQ: 'user:' + this.attrs.user.username()
    });
  }
}
flarum.reg.add('flarum-audit', 'forum/components/UserAuditModal', UserAuditModal);